data.query:
query MetaobjectByHandle($type: String!, $handle: String!) {
    metaobjectByHandle(handle: {type: $type, handle: $handle}) {
        id
        handle
        type
        displayName
        createdAt
        updatedAt
        capabilities {
            publishable {
                status
            }
            onlineStore {
                templateSuffix
            }
        }
        fields {
            key
            type
            value
            jsonValue
        }
    }
}
